1	"""
2	Apply Task 1 (Accessibility), Task 2 (Dead URL Detection), and Task 3 (Auth UI)
3	patches to live_dashboard.html and live_server.py.
4	
5	Run: python scripts/apply_dashboard_patches.py
6	"""
7	
8	import re
9	import sys
10	from pathlib import Path
11	
12	DASHBOARD_PATH = Path(__file__).parent / "templates" / "live_dashboard.html"
13	SERVER_PATH = Path(__file__).parent / "live_server.py"
14	
15	
16	def patch_dashboard():
17	    """Apply accessibility + auth UI patches to live_dashboard.html."""
18	    content = DASHBOARD_PATH.read_text(encoding="utf-8")
19	    original = content
20	
21	    # =========================================================================
22	    # TASK 1A: CSS for skip-link + keyboard focus on ev-card + example-card
23	    # TASK 3A: CSS for auth modal, auth button, history panel
24	    # Insert before </head>
25	    # =========================================================================
26	    css_block = """
27	/* =======================================================================
28	   Accessibility: Skip Navigation Link (I.3)
29	   ======================================================================= */
30	.skip-link {
31	  position: absolute;
32	  top: -40px;
33	  left: 0;
34	  padding: 8px 16px;
35	  background: var(--success);
36	  color: #fff;
37	  z-index: 10000;
38	  font-size: 14px;
39	  font-weight: 600;
40	  text-decoration: none;
41	  transition: top 0.2s var(--ease);
42	  border-radius: 0 0 var(--radius-sm) 0;
43	}
44	.skip-link:focus { top: 0; }
45	
46	/* Keyboard focus styles for interactive cards */
47	.ev-card:focus-visible,
48	.example-card:focus-visible,
49	.depth-chip:focus-visible,
50	.view-mode-btn:focus-visible,
51	.detail-panel-close:focus-visible,
52	.landing-submit-btn:focus-visible,
53	.user-progress-cancel:focus-visible {
54	  outline: 2px solid var(--accent);
55	  outline-offset: 2px;
56	}
57	
58	/* =======================================================================
59	   Auth UI Styles (2B.1)
60	   ======================================================================= */
61	.auth-button {
62	  padding: 4px 12px;
63	  font-size: 11px;
64	  font-family: var(--font-sans);
65	  font-weight: 500;
66	  color: var(--text-secondary);
67	  background: var(--bg-inset);
68	  border: 1px solid var(--border);
69	  border-radius: var(--radius-sm);
70	  cursor: pointer;
71	  transition: all var(--duration-fast) var(--ease);
72	  white-space: nowrap;
73	  margin-left: var(--sm);
74	}
75	.auth-button:hover {
76	  color: var(--accent);
77	  border-color: var(--accent);
78	  background: var(--accent-dim);
79	}
80	.auth-button:focus-visible {
81	  outline: 2px solid var(--accent);
82	  outline-offset: 2px;
83	}
84	
85	/* Auth Modal Overlay */
86	#auth-modal {
87	  display: none;
88	  position: fixed;
89	  inset: 0;
90	  z-index: 9999;
91	  background: rgba(0, 0, 0, 0.6);
92	  backdrop-filter: blur(4px);
93	  align-items: center;
94	  justify-content: center;
95	}
96	#auth-modal.visible { display: flex; }
97	
98	.auth-modal-content {
99	  background: var(--bg-elevated);
100	  border: 1px solid var(--border-active);
101	  border-radius: var(--radius-xl);
102	  padding: var(--xl);
103	  width: 100%;
104	  max-width: 380px;
105	  box-shadow: var(--shadow-lg);
106	}
107	.auth-modal-content h2 {
108	  font-size: var(--text-xl);
109	  color: var(--text-primary);
110	  margin-bottom: var(--lg);
111	  text-align: center;
112	}
113	.auth-modal-content .auth-field {
114	  display: block;
115	  width: 100%;
116	  padding: 10px 14px;
117	  margin-bottom: var(--md);
118	  background: var(--bg-inset);
119	  border: 1px solid var(--border);
120	  border-radius: var(--radius);
121	  color: var(--text-primary);
122	  font-size: 14px;
123	  font-family: var(--font-sans);
124	}
125	.auth-modal-content .auth-field:focus {
126	  outline: none;
127	  border-color: var(--accent);
128	  box-shadow: 0 0 0 2px var(--accent-dim);
129	}
130	.auth-modal-content .auth-submit-btn {
131	  display: block;
132	  width: 100%;
133	  padding: 10px;
134	  background: var(--accent);
135	  color: #0f172a;
136	  border: none;
137	  border-radius: var(--radius);
138	  font-size: 14px;
139	  font-weight: 600;
140	  font-family: var(--font-sans);
141	  cursor: pointer;
142	  transition: opacity var(--duration-fast) var(--ease);
143	}
144	.auth-modal-content .auth-submit-btn:hover { opacity: 0.9; }
145	.auth-modal-content .auth-submit-btn:focus-visible {
146	  outline: 2px solid var(--accent);
147	  outline-offset: 2px;
148	}
149	.auth-modal-content .auth-error {
150	  display: none;
151	  color: var(--error);
152	  font-size: 12px;
153	  margin-top: var(--sm);
154	  text-align: center;
155	}
156	.auth-modal-close {
157	  position: absolute;
158	  top: var(--md);
159	  right: var(--md);
160	  background: none;
161	  border: none;
162	  color: var(--text-tertiary);
163	  font-size: 20px;
164	  cursor: pointer;
165	}
166	.auth-modal-close:hover { color: var(--text-primary); }
167	
168	/* History Panel */
169	.history-panel {
170	  display: none;
171	  margin-top: var(--lg);
172	  max-width: 600px;
173	  width: 100%;
174	}
175	.history-panel.visible { display: block; }
176	.history-panel-title {
177	  font-size: var(--text-sm);
178	  font-weight: 600;
179	  color: var(--text-secondary);
180	  margin-bottom: var(--sm);
181	}
182	.history-list {
183	  display: flex;
184	  flex-direction: column;
185	  gap: var(--xs);
186	}
187	.history-item {
188	  display: flex;
189	  align-items: center;
190	  gap: var(--md);
191	  padding: var(--sm) var(--md);
192	  background: var(--bg-card);
193	  border: 1px solid var(--border);
194	  border-radius: var(--radius);
195	  cursor: pointer;
196	  transition: all var(--duration-fast) var(--ease);
197	}
198	.history-item:hover {
199	  border-color: var(--accent);
200	  background: var(--accent-dim);
201	}
202	.history-item:focus-visible {
203	  outline: 2px solid var(--accent);
204	  outline-offset: 2px;
205	}
206	.history-item-query {
207	  flex: 1;
208	  font-size: 13px;
209	  color: var(--text-primary);
210	  overflow: hidden;
211	  text-overflow: ellipsis;
212	  white-space: nowrap;
213	}
214	.history-item-meta {
215	  font-size: 11px;
216	  color: var(--text-tertiary);
217	  white-space: nowrap;
218	}
219	.history-item-status {
220	  font-size: 10px;
221	  font-weight: 600;
222	  padding: 2px 8px;
223	  border-radius: 10px;
224	}
225	.history-item-status.completed { background: var(--success-dim); color: var(--success); }
226	.history-item-status.failed { background: var(--error-dim); color: var(--error); }
227	.history-item-status.running { background: var(--accent-dim); color: var(--accent); }
228	
229	"""
230	    # Insert CSS before </head>
231	    content = content.replace("</head>", css_block + "</head>", 1)
232	
233	    # =========================================================================
234	    # TASK 1B: Skip-to-content link at top of body
235	    # =========================================================================
236	    content = content.replace(
237	        "<body>\n",
238	        '<body>\n<a href="#main-content" class="skip-link" '
239	        'onfocus="this.style.top=\'0\'" onblur="this.style.top=\'-40px\'">Skip to content</a>\n',
240	        1,
241	    )
242	
243	    # =========================================================================
244	    # TASK 1C: Add id="main-content" to the views-container
245	    # =========================================================================
246	    content = content.replace(
247	        '<div class="views-container">',
248	        '<div class="views-container" id="main-content">',
249	        1,
250	    )
251	
252	    # =========================================================================
253	    # TASK 1D: Add role="img" and aria-label to the graph-svg
254	    # =========================================================================
255	    content = content.replace(
256	        '<svg id="graph-svg"></svg>',
257	        '<svg id="graph-svg" role="img" aria-label="Evidence relationship graph visualization"></svg>',
258	        1,
259	    )
260	
261	    # =========================================================================
262	    # TASK 1E: Add aria-label to dynamically built SVGs (faithfulness gauge)
263	    # In buildFaithGauge, add role="img" and aria-label
264	    # =========================================================================
265	    content = content.replace(
266	        "return '<div class=\"faith-gauge-circle\"><svg width=\"' + size + '\" height=\"' + size + '\" viewBox=\"0 0 ' + size + ' ' + size + '\">'",
267	        "return '<div class=\"faith-gauge-circle\"><svg role=\"img\" aria-label=\"Faithfulness gauge: ' + pctStr + '\" width=\"' + size + '\" height=\"' + size + '\" viewBox=\"0 0 ' + size + ' ' + size + '\">'",
268	        1,
269	    )
270	
271	    # =========================================================================
272	    # TASK 1F: Add aria-label to buildSignalRadar SVG
273	    # =========================================================================
274	    content = content.replace(
275	        "var svg = '<svg width=\"' + size + '\" height=\"' + size + '\" viewBox=\"0 0 ' + size + ' ' + size + '\">';",
276	        "var svg = '<svg role=\"img\" aria-label=\"5-signal radar chart showing evidence quality scores\" width=\"' + size + '\" height=\"' + size + '\" viewBox=\"0 0 ' + size + ' ' + size + '\">';",
277	        1,
278	    )
279	
280	    # =========================================================================
281	    # TASK 1G: Add aria-label to the detail panel radar SVG
282	    # =========================================================================
283	    content = content.replace(
284	        "var radarSvg = '<svg width=\"160\" height=\"175\" viewBox=\"0 0 160 175\" style=\"display:block;margin:0 auto var(--sm)\">';",
285	        "var radarSvg = '<svg role=\"img\" aria-label=\"5-signal radar chart for this evidence\" width=\"160\" height=\"175\" viewBox=\"0 0 160 175\" style=\"display:block;margin:0 auto var(--sm)\">';",
286	        1,
287	    )
288	
289	    # =========================================================================
290	    # TASK 1H: Keyboard support for example-cards (tabindex + onkeydown)
291	    # =========================================================================
292	    content = content.replace(
293	        '<div class="example-card" onclick="useExample(this)">',
294	        '<div class="example-card" tabindex="0" role="button" onclick="useExample(this)" onkeydown="if(event.key===\'Enter\'||event.key===\' \'){this.click();event.preventDefault();}">',
295	    )
296	
297	    # =========================================================================
298	    # TASK 1I: Keyboard support for depth-chips
299	    # =========================================================================
300	    content = content.replace(
301	        '<button class="depth-chip" data-depth="quick" onclick="setDepth(\'quick\')">',
302	        '<button class="depth-chip" data-depth="quick" onclick="setDepth(\'quick\')" onkeydown="if(event.key===\'Enter\'||event.key===\' \'){this.click();event.preventDefault();}">',
303	    )
304	    content = content.replace(
305	        '<button class="depth-chip active" data-depth="standard" onclick="setDepth(\'standard\')">',
306	        '<button class="depth-chip active" data-depth="standard" onclick="setDepth(\'standard\')" onkeydown="if(event.key===\'Enter\'||event.key===\' \'){this.click();event.preventDefault();}">',
307	    )
308	    content = content.replace(
309	        '<button class="depth-chip" data-depth="deep" onclick="setDepth(\'deep\')">',
310	        '<button class="depth-chip" data-depth="deep" onclick="setDepth(\'deep\')" onkeydown="if(event.key===\'Enter\'||event.key===\' \'){this.click();event.preventDefault();}">',
311	    )
312	
313	    # =========================================================================
314	    # TASK 1J: Make ev-cards keyboard-accessible via JS
315	    # In renderEvidenceCards, the onclick is in JS-generated HTML.
316	    # We add tabindex="0" and onkeydown to ev-card divs.
317	    # =========================================================================
318	    content = content.replace(
319	        "var html = '<div class=\"ev-card\" onclick=\"selectEvidenceFromCard(\\'' + esc(p.id || \"\") + '\\')\">';",
320	        "var html = '<div class=\"ev-card\" tabindex=\"0\" role=\"button\" onclick=\"selectEvidenceFromCard(\\'' + esc(p.id || \"\") + '\\')\" onkeydown=\"if(event.key===\\'Enter\\'||event.key===\\' \\'){this.click();event.preventDefault();}\">';",
321	    )
322	
323	    # =========================================================================
324	    # TASK 3B: Auth button in header (next to view mode toggle)
325	    # Insert after the header-meta div opening
326	    # =========================================================================
327	    content = content.replace(
328	        '  <div class="header-meta">',
329	        '  <button class="auth-button" id="auth-button" style="display:none" '
330	        'onclick="toggleAuthModal()" aria-label="Sign in or view account">Sign In</button>\n'
331	        '  <div class="header-meta">',
332	        1,
333	    )
334	
335	    # =========================================================================
336	    # TASK 3C: Auth modal + history panel HTML (before toast container)
337	    # =========================================================================
338	    auth_html = """
339	<!-- ===================================================================
340	     AUTH MODAL (2B.1) — Hidden when auth not enabled
341	     =================================================================== -->
342	<div id="auth-modal" aria-modal="true" role="dialog" aria-labelledby="auth-modal-title">
343	  <div class="auth-modal-content" style="position:relative">
344	    <button class="auth-modal-close" onclick="closeAuthModal()" aria-label="Close sign-in dialog">&times;</button>
345	    <h2 id="auth-modal-title">Sign In</h2>
346	    <form onsubmit="handleLogin(event)" novalidate>
347	      <label for="auth-username" class="sr-only" style="position:absolute;width:1px;height:1px;overflow:hidden;clip:rect(0,0,0,0)">Username</label>
348	      <input type="text" id="auth-username" class="auth-field" placeholder="Username" required autocomplete="username">
349	      <label for="auth-password" class="sr-only" style="position:absolute;width:1px;height:1px;overflow:hidden;clip:rect(0,0,0,0)">Password</label>
350	      <input type="password" id="auth-password" class="auth-field" placeholder="Password" required autocomplete="current-password">
351	      <button type="submit" class="auth-submit-btn">Sign In</button>
352	    </form>
353	    <div class="auth-error" id="auth-error"></div>
354	  </div>
355	</div>
356	
357	"""
358	    content = content.replace(
359	        '<!-- Toast container -->',
360	        auth_html + '<!-- Toast container -->',
361	        1,
362	    )
363	
364	    # =========================================================================
365	    # TASK 3D: History panel in the landing page (after examples, before "how it works")
366	    # =========================================================================
367	    history_html = """
368	  <div class="history-panel" id="history-panel">
369	    <div class="history-panel-title">Recent Research</div>
370	    <div class="history-list" id="history-list"></div>
371	  </div>
372	
373	"""
374	    content = content.replace(
375	        '  <div class="landing-how">',
376	        history_html + '  <div class="landing-how">',
377	        1,
378	    )
379	
380	    # =========================================================================
381	    # TASK 3E: Auth JavaScript (before closing </script>)
382	    # =========================================================================
383	    auth_js = """
384	/* =====================================================================
385	   AUTH UI — Login/Logout/History (2B.1)
386	   ===================================================================== */
387	var _authEnabled = false;
388	
389	function initAuth() {
390	  fetch("/api/auth/status")
391	  .then(function(r) { return r.json(); })
392	  .then(function(data) {
393	    _authEnabled = data.auth_enabled === true;
394	    if (_authEnabled) {
395	      document.getElementById("auth-button").style.display = "inline-flex";
396	      var token = localStorage.getItem("polaris_token");
397	      if (token) {
398	        checkAuthToken(token);
399	      }
400	    }
401	  })
402	  .catch(function() {
403	    // Auth endpoint not available, keep hidden
404	  });
405	}
406	
407	function checkAuthToken(token) {
408	  fetch("/api/auth/me", {
409	    headers: {"Authorization": "Bearer " + token}
410	  })
411	  .then(function(r) {
412	    if (r.ok) return r.json();
413	    throw new Error("invalid");
414	  })
415	  .then(function(data) {
416	    state.authenticated = true;
417	    state.user = data;
418	    updateAuthUI();
419	    loadResearchHistory();
420	  })
421	  .catch(function() {
422	    localStorage.removeItem("polaris_token");
423	    state.authenticated = false;
424	    state.user = null;
425	    updateAuthUI();
426	  });
427	}
428	
429	function toggleAuthModal() {
430	  if (state.authenticated) {
431	    handleLogout();
432	  } else {
433	    openAuthModal();
434	  }
435	}
436	
437	function openAuthModal() {
438	  var modal = document.getElementById("auth-modal");
439	  modal.classList.add("visible");
440	  setTimeout(function() {
441	    document.getElementById("auth-username").focus();
442	  }, 100);
443	}
444	
445	function closeAuthModal() {
446	  document.getElementById("auth-modal").classList.remove("visible");
447	  document.getElementById("auth-error").style.display = "none";
448	  document.getElementById("auth-username").value = "";
449	  document.getElementById("auth-password").value = "";
450	}
451	
452	function handleLogin(e) {
453	  e.preventDefault();
454	  var username = document.getElementById("auth-username").value;
455	  var password = document.getElementById("auth-password").value;
456	  var errorEl = document.getElementById("auth-error");
457	  errorEl.style.display = "none";
458	
459	  fetch("/api/auth/login", {
460	    method: "POST",
461	    headers: {"Content-Type": "application/json"},
462	    body: JSON.stringify({username: username, password: password})
463	  })
464	  .then(function(r) {
465	    if (r.ok) return r.json();
466	    return r.json().then(function(d) { throw new Error(d.detail || "Invalid credentials"); });
467	  })
468	  .then(function(data) {
469	    localStorage.setItem("polaris_token", data.token);
470	    state.authenticated = true;
471	    state.user = {username: data.username, role: data.role};
472	    closeAuthModal();
473	    showToast("Signed in as " + data.username, "success");
474	    updateAuthUI();
475	    loadResearchHistory();
476	  })
477	  .catch(function(err) {
478	    errorEl.textContent = err.message || "Login failed";
479	    errorEl.style.display = "block";
480	  });
481	}
482	
483	function handleLogout() {
484	  localStorage.removeItem("polaris_token");
485	  state.authenticated = false;
486	  state.user = null;
487	  updateAuthUI();
488	  var histPanel = document.getElementById("history-panel");
489	  if (histPanel) histPanel.classList.remove("visible");
490	  showToast("Signed out", "info");
491	}
492	
493	function updateAuthUI() {
494	  var authBtn = document.getElementById("auth-button");
495	  if (!authBtn) return;
496	  if (state.authenticated && state.user) {
497	    authBtn.textContent = state.user.username || "User";
498	    authBtn.setAttribute("aria-label", "Signed in as " + (state.user.username || "User") + ". Click to sign out.");
499	  } else {
500	    authBtn.textContent = "Sign In";
501	    authBtn.setAttribute("aria-label", "Sign in or view account");
502	  }
503	}
504	
505	function loadResearchHistory() {
506	  var token = localStorage.getItem("polaris_token");
507	  if (!token) return;
508	  fetch("/api/auth/history", {
509	    headers: {"Authorization": "Bearer " + token}
510	  })
511	  .then(function(r) {
512	    if (r.ok) return r.json();
513	    throw new Error("unauthorized");
514	  })
515	  .then(function(history) {
516	    renderHistoryPanel(history);
517	  })
518	  .catch(function(err) {
519	    console.warn("Failed to load research history:", err);
520	  });
521	}
522	
523	function renderHistoryPanel(sessions) {
524	  var panel = document.getElementById("history-panel");
525	  var list = document.getElementById("history-list");
526	  if (!panel || !list) return;
527	  if (!sessions || !sessions.length) { panel.classList.remove("visible"); return; }
528	
529	  panel.classList.add("visible");
530	  var items = sessions.slice(0, 10);
531	  list.innerHTML = items.map(function(s) {
532	    var query = esc(truncStr(s.query || "Untitled", 80));
533	    var statusCls = (s.status || "").toLowerCase();
534	    var statusText = (s.status || "unknown").toUpperCase();
535	    var dateStr = "";
536	    if (s.created_at) {
537	      var d = new Date(s.created_at * 1000);
538	      dateStr = d.toLocaleDateString() + " " + d.toLocaleTimeString([], {hour: "2-digit", minute: "2-digit"});
539	    }
540	    return '<div class="history-item" tabindex="0" role="button" ' +
541	      'onclick="loadHistoryItem(\\'' + esc(s.vector_id || "") + '\\')" ' +
542	      'onkeydown="if(event.key===\\'Enter\\'||event.key===\\' \\'){this.click();event.preventDefault();}" ' +
543	      'aria-label="View research: ' + query + '">' +
544	      '<span class="history-item-status ' + statusCls + '">' + statusText + '</span>' +
545	      '<span class="history-item-query">' + query + '</span>' +
546	      '<span class="history-item-meta">' + esc(dateStr) + '</span>' +
547	      '</div>';
548	  }).join("");
549	}
550	
551	function loadHistoryItem(vectorId) {
552	  if (!vectorId) return;
553	  fetch("/api/research/result/" + encodeURIComponent(vectorId))
554	  .then(function(r) {
555	    if (r.ok) return r.json();
556	    throw new Error("not found");
557	  })
558	  .then(function(data) {
559	    state.pipelineComplete = true;
560	    state.vectorId = vectorId;
561	    if (data.final_report) state.fullReport = data.final_report;
562	    if (data.bibliography) state.bibliography = data.bibliography;
563	    updateUIVisibility();
564	    switchView("report");
565	    showToast("Loaded research: " + (data.query || vectorId), "info");
566	  })
567	  .catch(function(err) {
568	    showToast("Could not load result: " + err.message, "error");
569	  });
570	}
571	
572	// Close auth modal on Escape key
573	document.addEventListener("keydown", function(e) {
574	  if (e.key === "Escape") {
575	    var modal = document.getElementById("auth-modal");
576	    if (modal && modal.classList.contains("visible")) {
577	      closeAuthModal();
578	    }
579	  }
580	});
581	
582	// Close auth modal on backdrop click
583	document.getElementById("auth-modal").addEventListener("click", function(e) {
584	  if (e.target === this) closeAuthModal();
585	});
586	
587	// Initialize auth on page load
588	initAuth();
589	
590	"""
591	    content = content.replace(
592	        "window._getDebugState = function() { return state; };",
593	        auth_js + "window._getDebugState = function() { return state; };",
594	        1,
595	    )
596	
597	    # =========================================================================
598	    # TASK 3F: Add auth state fields to the state object
599	    # =========================================================================
